#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        long long ans = 1;
        if (M > N - M) M = N - M;
        for (int i = 1; i <= M; ++i) {
            ans = ans * (N - M + i) / i;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

